A,EACpD,QAAA,EAAA,WAAA,CAAY,GAAA,CAAI,CAAC,MAAA,qBAChBA,GAAAA;AAAA,IAAC,GAAA;AAAA,IAAA;AAAA,MAEC,MAAM,MAAA,CAAO,IAAA;AAAA,MACb,MAAA,EAAO,QAAA;AAAA,MACP,GAAA,EAAI,qBAAA;AAAA,MACJ,cAAY,MAAA,CAAO,KAAA;AAAA,MACnB,SAAA,EAAU,6DAAA;AAAA,MAEV,0BAAAA,GAAAA,CAAC,MAAA,EAAA,EAAK,SAAA,EAAU,0CAAA,EACb,iBAAO,IAAA,EACV;AAAA,KAAA;AAAA,IATK,MAAA,CAAO;AAAA,GAWf,CAAA,EACH,CAAA;AAEJ,CAAA;ACvCA,IAAM,IAAA,GAAA,iBAAO,IAAI,IAAA,EAAK,EAAE,WAAA,EAAY;AAE7B,IAAM,YAAA,GAAe,CAAC,EAAE,WAAA,uBAC7BD,IAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,OAAA,EAIb,QAAA,EAAA;AAAA,kBAAAC,GAAAA,CAAC,SAAI,SAAA,EAAU,0BAAA,EACb,0BAAAA,GAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,wBAAA,EAAyB,CAAA,EAC1C,CAAA;AAAA,kBAEAD,IAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,8DAAA,EAEb,QAAA,EAAA;AAAA,oBAAAC,GAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,QAAA,EACb,QAAA,kBAAAD,IAAAA,CAACE,IAAAA,EAAA,EAAK,IAAA,EAAK,MAAA,EAAO,SAAA,EAAU,2CAAA,EAA4C,QAAA,EAAA;AAAA,MAAA,OAAA;AAAA,MACnE,IAAA;AAAA,MAAK;AAAA,KAAA,EACV,CAAA,EACF,CAAA;AAAA,oBAGAD,GAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,4BAAA,EACb,QAAA,kBAAAA,GAAAA,CAAC,QAAA,EAAA,EAAO,SAAA,EAAU,yGAAA,EAA0G,QAAA,EAAA,cAAA,EAE5H,CAAA,EACF,CAAA;AAAA,oBAGAA,GAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,yBAAA,EACb,0BAAAA,GAAAA,CAAC,aAAA,EAAA,EAAc,KAAA,EAAO,WAAA,EAAa,CAAA,EACrC;AAAA,GAAA,EACF;AAAA,CAAA,EACF,CAAA;AC3BK,IAAM,YAAA,GAA4C,KAAK,CAAC;AAAA,EAC7D,SAAA;AAAA,EACA,kBAAA;AAAA,EACA,aAAA,GAAgB,IAAA;AAAA,EAChB,YAAA,GAAe,QAAA;AAAA,EACf;AACF,CAAA,KAAM;AACJ,EAAA,MAAM,KAAA,GAAQ;AAAA,IACZ,OAAA,EAAS,WAAA,EAAa,OAAA,IAAW,KAAA,CAAM,OAAA;AAAA,IACvC,SAAA,EAAW,WAAA,EAAa,SAAA,IAAa,KAAA,CAAM,SAAA;AAAA,IAC3C,QAAA,EAAU,WAAA,EAAa,QAAA,IAAY,KAAA,CAAM;AAAA,GAC3C;AAEA,EAAA,uBACED,IAAAA,CAAC,QAAA,EAAA,EAAO,WAAWG,KAAAA,CAAK,wCAAA,EAA0C,SAAS,CAAA,EAExE,QAAA,EAAA;AAAA,IAAA,aAAA,oBACCF,GAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,qDAAA,EAAsD,CAAA;AAAA,oBAMvEA,GAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,kDAAA,EACb,QAAA,kBAAAD,IAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAWG,KAAAA,CAAK,gBAAA,EAAkB,kBAAkB,CAAA,EACvD,QAAA,EAAA;AAAA,sBAAAH,IAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,8DAAA,EAGb,QAAA,EAAA;AAAA,wBAAAA,IAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,mCAAA,EACb,QAAA,EAAA;AAAA,0BAAAC,GAAAA,CAAC,WAAA,EAAA,EAAY,OAAA,EAAS,YAAA,EAAc,CAAA;AAAA,0BAEpCD,IAAAA,CAAC,QAAA,EAAA,EAAO,SAAA,EAAU,uIAAA,EAChB,QAAA,EAAA;AAAA,4BAAAC,GAAAA,CAAC,MAAA,EAAA,EAAK,SAAA,EAAU,qBAAA,EAAsB,QAAA,EAAA,QAAA,EAAC,CAAA;AAAA,4BACvCA,GAAAA,CAAC,MAAA,EAAA,EAAK,SAAA,EAAU,2CAA0C,QAAA,EAAA,YAAA,EAAU;AAAA,WAAA,EACtE;AAAA,SAAA,EACF,CAAA;AAAA,wBAGAD,IAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,2DAAA,EACb,QAAA,EAAA;AAAA,0BAAAC,IAAC,YAAA,EAAA,EAAa,KAAA,EAAM,SAAA,EAAU,KAAA,EAAO,aAAa,OAAA,EAAS,CAAA;AAAA,0BAC3DA,GAAAA,CAAC,YAAA,EAAA,EAAa,OAAM,WAAA,EAAY,KAAA,EAAO,aAAa,SAAA,EAAW,CAAA;AAAA,0BAC/DA,GAAAA,CAAC,YAAA,EAAA,EAAa,OAAM,OAAA,EAAQ,KAAA,EAAO,aAAa,KAAA,EAAO,CAAA;AAAA,0BACvDA,GAAAA,CAAC,YAAA,EAAA,EAAa,OAAM,YAAA,EAAa,KAAA,EAAO,aAAa,UAAA,EAAY;AAAA,SAAA,EACnE;AAAA,OAAA,EACF,CAAA;AAAA,sBAEAA,GAAAA,CAAC,YAAA,EAAA,EAAa,WAAA,EAAa,KAAA,EAAO;AAAA,KAAA,EACpC,CAAA,EACF;AAAA,GAAA,EACF,CAAA;AAEJ,CAAC;AAED,YAAA,CAAa,WAAA,GAAc,cAAA;AClD3B,IAAM,iBAAA,GAAoB;AAAA,EAC1B,OAAA,EAAS,wBAAA;AAAA;AAAA,EAGT,SAAA,EAAW,wBAAA;AAAA,EAEX,IAAA,EAAM;AACN,CAAA;AAEO,IAAM,oBAAgD,CAAC;AAAA,EAC9D,IAAA;AAAA,EACA,MAAA;AAAA,EACA,KAAA;AAAA,EACA,SAAA;AAAA,EACA,OAAA,GAAU;AACV,CAAA,KAAM;AACN,EAAA,uBACAD,IAAAA;AAAA,IAAC,QAAA;AAAA,IAAA;AAAA,MACD,IAAA,EAAK,QAAA;AAAA,MACL,SAAA,EAAWG,IAAAA;AAAA,QACX,wCAAA;AAAA,QACA,kBAAA;AAAA,QACA,4BAAA;AAAA,QACA;AAAA,OACA;AAAA,MAEA,QAAA,EAAA;AAAA,wBAAAH,IAAAA;AAAA,UAAC,KAAA;AAAA,UAAA;AAAA,YACD,SAAA,EAAWG,IAAAA;AAAA,cACX,kBAAkB,OAAO,CAAA;AAAA;AAAA,cAGnB,8BAAA;AAAA,cAEA;AAAA,aACF;AAAA,YACA,YAAA,EAAW,SAAA;AAAA,YAGX,QAAA,EAAA;AAAA,8BAAAF,GAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,iCAAA,EACZ,QAAA,EAAA,IAAA,EACH,CAAA;AAAA,8BAGAA,GAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,qDACZ,QAAA,EAAA,MAAA,EACH,CAAA;AAAA,8BAGAA,GAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,8DACZ,QAAA,EAAA,KAAA,EACH;AAAA;AAAA;AAAA,SACF;AAAA,wBAGAA,GAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,4EACb,QAAA,kBAAAA,GAAAA;AAAA,UAAC,KAAA;AAAA,UAAA;AAAA,YACC,SAAA,EAAU;AAAA;AAAA,SAQZ,EACF;AAAA;AAAA;AAAA,GACF;AAIA,CAAA;AAEeG,KAAK,iBAAiB;ACxE9B,IAAM,eAA4C,CAAC;AAAA,EACxD,SAAA;AAAA,EACA;AACF,CAAA,KAAM;AACJ,EAAA,uBACEH,GAAAA;AAAA,IAAC,iBAAA;AAAA,IAAA;AAAA,MACC,SAAA;AAAA,MACA,OAAA,EAAQ,WAAA;AAAA,MACR,sBACEA,GAAAA;AAAA,QAAC,IAAA;AAAA,QAAA;AAAA,UACC,IAAII,MAAAA,CAAO,IAAA;AAAA,UACX,SAAA,EAAU,+BAAA;AAAA,UAEV,QAAA,kBAAAJ,GAAAA;AAAA,YAACK,IAAAA;AAAA,YAAA;AAAA,cACC,OAAA,EAAQ,QAAA;AAAA,cACR,IAAA,EAAK,IAAA;AAAA,cAGL,aAAA,EAAc,iKAAA;AAAA,cAOd,iBAAA,EAAkB;AAAA;AAAA;AAGpB;AAAA,OACF;AAAA,MAEF,MAAA;AAAA,MACA,KAAA,kBACEN,IAAAA,CAAC,KAAA,EAAA,EAAI,WAAU,kCAAA,EAEb,QAAA,EAAA;AAAA,wBAAAC,GAAAA;AAAA,UAAC,MAAA;AAAA,UAAA;AAAA,YACC,EAAA,EAAI,IAAA;AAAA,YACJ,IAAII,MAAAA,CAAO,KAAA;AAAA,YACX,OAAA,EAAQ,WAAA;AAAA,YACR,IAAA,EAAK,IAAA;AAAA,YACL,SAAA,EAAU,MAAA;AAAA,YACX,QAAA,EAAA;AAAA;AAAA,SAED;AAAA,wBAGAJ,GAAAA;AAAA,UAAC,MAAA;AAAA,UAAA;AAAA,YACC,EAAA,EAAI,IAAA;AAAA,YACJ,IAAII,MAAAA,CAAO,MAAA;AAAA,YACX,OAAA,EAAQ,SAAA;AAAA,YACR,IAAA,EAAK,IAAA;AAAA,YACL,SAAA,EAAU,mBAAA;AAAA,YACX,QAAA,EAAA;AAAA;AAAA;AAED,OAAA,EACF;AAAA;AAAA,GAEJ;AAEJ,CAAA;AC1DO,IAAM,iBAAgD,CAAC;AAAA,EAC5D,QAAA;AAAA,EACA,SAAA;AAAA,EACA,UAAA,GAAa,IAAA;AAAA,EACb,UAAA,GAAa;AACf,CAAA,KAAM;AACJ,EAAA,uBACEL,IAAAA;AAAA,IAAC,KAAA;AAAA,IAAA;AAAA,MACC,SAAA,EAAWG,KAAAA;AAAA,QACT,wEAAA;AAAA,QACA,8CAAA;AAAA,QACA;AAAA,OACF;AAAA,MAGC,QAAA,EAAA;AAAA,QAAA,UAAA,oBAAcF,IAAC,YAAA,EAAA,EAAa,CAAA;AAAA,wBAG7BA,GAAAA,CAAC,MAAA,EAAA,EAAK,SAAA,EAAU,4BAAA,EAGd,0BAAAA,GAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,oBAAA,EACb,0BAAAA,GAAAA,CAAC,KAAA,EAAA,EAAI,WAAU,iCAAA,EACZ,QAAA,EACH,GACF,CAAA,EACF,CAAA;AAAA,QAGC,UAAA,oBACCA,GAAAA,CAAC,KAAA,EAAA,EAAI,WAAU,UAAA,EACb,QAAA,kBAAAA,GAAAA,CAAC,YAAA,EAAA,EAAa,CAAA,EAChB;AAAA;AAAA;AAAA,GAEJ;AAEJ","file":"index.js","sourcesContent":["import React from \"react\";\nimport { Text } from \"@unio/ui\";\nimport { FooterLinkItem } from \"./types\";\n\nexport const FooterColumn: React.FC<{ title: string; items: readonly FooterLinkItem[] }> = ({ title, items }) => {\n  if (!items?.length) return null;\n  return (\n    <div className=\"flex flex-col gap-4 min-w-[120px]\">\n      <Text className=\"text-sm font-semibold text-text-primary\">\n        {title}\n      </Text>\n      <ul className=\"flex flex-col gap-2\">\n        {items.map(({ href, label }) => (\n          <li key={label}>\n            <a href={href} className=\"text-sm text-text-secondary hover:text-accent transition-colors\">\n              {label}\n            </a>\n          </li>\n        ))}\n      </ul>\n    </div>\n  );\n};","import React from \"react\";\nimport { Text, Logo } from \"@unio/ui\";\nimport { ROUTES } from \"@unio/lib\";\n\nexport const FooterBrand: React.FC<{ variant: \"lockup\" | \"mark\" | \"wordmark\" }> = ({ variant }) => (\n  <div className=\"flex flex-col gap-4\">\n    <a href={ROUTES.HOME} className=\"inline-block w-fit group\">\n      <Logo \n        variant={variant} \n        size=\"sm\" \n        /* Smaller icon: set to roughly 0.9rem or 1rem \n        */\n        iconClassName=\"text-[1rem] text-accent\" \n        /* Bolder and larger name: \n           - font-bold/font-semibold for the bold look\n           - text-[1.2rem] to make it larger than the icon\n        */\n        wordmarkClassName=\"text-[1.2rem] font-bold text-text-primary tracking-tight\"\n      />\n    </a>\n    <Text className=\"text-[13px] text-text-secondary leading-relaxed max-w-[280px]\">\n      Redefining connection — powered by intelligence, inspired by people.\n    </Text>\n  </div>\n);","import React from \"react\";\nimport { FiTwitter, FiInstagram, FiLinkedin } from \"react-icons/fi\";\nimport { clsx, type ClassValue } from \"clsx\";\nimport { twMerge } from \"tailwind-merge\";\n\nfunction cn(...inputs: ClassValue[]) {\n  return twMerge(clsx(inputs));\n}\n\ninterface FooterSocialsProps {\n  links: {\n    twitter: string;\n    instagram: string;\n    linkedin: string;\n  };\n  className?: string;\n}\n\nexport const FooterSocials: React.FC<FooterSocialsProps> = ({ links, className }) => {\n  const socialItems = [\n    { icon: <FiTwitter />, href: links.twitter, label: \"Twitter\" },\n    { icon: <FiInstagram />, href: links.instagram, label: \"Instagram\" },\n    { icon: <FiLinkedin />, href: links.linkedin, label: \"LinkedIn\" },\n  ];\n\n  return (\n    <div className={cn(\"flex items-center gap-2\", className)}>\n      {socialItems.map((social) => (\n        <a\n          key={social.label}\n          href={social.href}\n          target=\"_blank\"\n          rel=\"noopener noreferrer\"\n          aria-label={social.label}\n          className=\"text-text-secondary hover:text-accent transition-colors p-1\"\n        >\n          <span className=\"text-lg flex items-center justify-center\">\n            {social.icon}\n          </span>\n        </a>\n      ))}\n    </div>\n  );\n};\n\nexport default FooterSocials;","import React from \"react\";\nimport { Text } from \"@unio/ui\";\nimport { FooterSocials } from \"./FooterSocials\";\n\nconst YEAR = new Date().getFullYear();\n\nexport const FooterBottom = ({ socialLinks }: { socialLinks: any }) => (\n  <div className=\"mt-12\">\n    {/* SCOOTED DIVIDER: Using w-[92%] or a slight margin \n        so it doesn't feel like it's touching the edges of the universe.\n    */}\n    <div className=\"flex justify-center mb-6\">\n      <div className=\"h-px w-[94%] bg-accent\" />\n    </div>\n\n    <div className=\"flex flex-col md:flex-row items-center justify-between gap-6\">\n      {/* LEFT: COPYRIGHT */}\n      <div className=\"flex-1\">\n        <Text size=\"tiny\" className=\"text-text-tertiary font-medium opacity-80\">\n          © {YEAR} Unio Technologies Inc. All rights reserved.\n        </Text>\n      </div>\n\n      {/* CENTER: LANGUAGE */}\n      <div className=\"flex-1 flex justify-center\">\n        <button className=\"text-[10px] font-bold uppercase tracking-[0.2em] text-text-tertiary hover:text-accent transition-colors\">\n          English (UK)\n        </button>\n      </div>\n\n      {/* RIGHT: SOCIALS */}\n      <div className=\"flex-1 flex justify-end\">\n        <FooterSocials links={socialLinks} />\n      </div>\n    </div>\n  </div>\n);","import React, { memo } from \"react\";\nimport clsx from \"clsx\";\nimport { LINKS, FOOTER_LINKS } from \"@unio/lib\";\nimport { PublicFooterProps } from \"./types\";\nimport { FooterColumn } from \"./FooterColumn\";\nimport { FooterBrand } from \"./FooterBrand\";\nimport { FooterBottom } from \"./FooterBottom\";\n\nexport const PublicFooter: React.FC<PublicFooterProps> = memo(({\n  className,\n  containerClassName,\n  showTopBorder = true,\n  brandVariant = \"lockup\",\n  socialLinks,\n}) => {\n  const links = {\n    twitter: socialLinks?.twitter ?? LINKS.TWITTER,\n    instagram: socialLinks?.instagram ?? LINKS.INSTAGRAM,\n    linkedin: socialLinks?.linkedin ?? LINKS.LINKEDIN,\n  };\n\n  return (\n    <footer className={clsx(\"w-full shrink-0 bg-background relative\", className)}>\n      {/* SHARP 1PX TOP BORDER */}\n      {showTopBorder && (\n        <div className=\"absolute top-0 left-0 right-0 h-px bg-accent w-full\" />\n      )}\n\n      {/* SCOOTED IN: Changed max-w-1600 to max-w-[1320px] \n          This brings the left and right sides closer to the center.\n      */}\n      <div className=\"max-w-[1320px] mx-auto px-[clamp(1rem,3vw,3rem)]\">\n        <div className={clsx(\"py-12 lg:py-16\", containerClassName)}>\n          <nav className=\"flex flex-col lg:flex-row justify-between items-start gap-12\">\n            \n            {/* LEFT: BRANDING & CONTACT */}\n            <div className=\"flex flex-col gap-6 max-w-[280px]\">\n              <FooterBrand variant={brandVariant} />\n              \n              <button className=\"flex items-center gap-2 w-fit px-4 py-2 rounded-lg border border-white/10 bg-white/5 hover:bg-white/10 transition-all active:scale-95\">\n                <span className=\"text-accent text-xs\">✎</span>\n                <span className=\"text-sm font-semibold text-text-primary\">Contact Us</span>\n              </button>\n            </div>\n\n            {/* RIGHT: NAVIGATION - Adjusted gaps to feel tighter */}\n            <div className=\"grid grid-cols-2 sm:grid-cols-4 gap-8 lg:gap-12 xl:gap-16\">\n              <FooterColumn title=\"Company\" items={FOOTER_LINKS.company} />\n              <FooterColumn title=\"Resources\" items={FOOTER_LINKS.resources} />\n              <FooterColumn title=\"Legal\" items={FOOTER_LINKS.legal} />\n              <FooterColumn title=\"Compliance\" items={FOOTER_LINKS.compliance} />\n            </div>\n          </nav>\n\n          <FooterBottom socialLinks={links} />\n        </div>\n      </div>\n    </footer>\n  );\n});\n\nPublicFooter.displayName = \"PublicFooter\";","import React, { memo } from \"react\";\nimport { clsx } from \"clsx\";\n\nexport interface HeaderShellProps {\nleft?: React.ReactNode;\ncenter?: React.ReactNode;\nright?: React.ReactNode;\nclassName?: string;\nvariant?: \"default\" | \"marketing\" | \"full\";\n}\n\nconst containerVariants = {\ndefault: \"max-w-[1128px] mx-auto\",\n\n/* 🔥 KEY CHANGE: MUCH WIDER */\nmarketing: \"max-w-[1600px] mx-auto\",\n\nfull: \"w-full\",\n};\n\nexport const PublicHeaderShell: React.FC<HeaderShellProps> = ({\nleft,\ncenter,\nright,\nclassName,\nvariant = \"marketing\",\n}) => {\nreturn (\n<header\nrole=\"banner\"\nclassName={clsx(\n\"fixed top-0 left-0 right-0 z-50 w-full\",\n\"backdrop-blur-xl\",\n\"bg-[hsl(var(--bg-0)/0.65)]\",\nclassName\n)}\n>\n<nav\nclassName={clsx(\ncontainerVariants[variant],\n\n      /* light padding so it doesn't hit edges */\n      \"px-[clamp(0.75rem,2vw,2rem)]\",\n\n      \"flex h-16 items-center justify-between\"\n    )}\n    aria-label=\"Primary\"\n  >\n    {/* LEFT */}\n    <div className=\"flex items-center min-w-[120px]\">\n      {left}\n    </div>\n\n    {/* CENTER */}\n    <div className=\"hidden md:flex flex-1 items-center justify-center\">\n      {center}\n    </div>\n\n    {/* RIGHT */}\n    <div className=\"flex items-center justify-end gap-3 sm:gap-4 min-w-[120px]\">\n      {right}\n    </div>\n  </nav>\n\n  {/* 🔥 CORRECT FADE ACCENT DIVIDER */}\n  <div className=\"pointer-events-none absolute bottom-0 left-0 right-0 flex justify-center\">\n    <div\n      className=\"\n        h-px\n        w-[92%]\n        bg-gradient-to-r\n        from-transparent\n        via-[hsl(var(--accent-1))]\n        to-transparent\n      \"\n    />\n  </div>\n</header>\n\n\n);\n};\n\nexport default memo(PublicHeaderShell);\n","import React from \"react\";\nimport { Link } from \"react-router-dom\";\nimport { Logo, Button } from \"@unio/ui\";\nimport { ROUTES } from \"@unio/lib\";\nimport { PublicHeaderShell } from \"./PublicHeaderShell\";\n\nexport type PublicHeaderProps = {\n  className?: string;\n  center?: React.ReactNode;\n};\n\nexport const PublicHeader: React.FC<PublicHeaderProps> = ({\n  className,\n  center,\n}) => {\n  return (\n    <PublicHeaderShell\n      className={className}\n      variant=\"marketing\"\n      left={\n        <Link\n          to={ROUTES.HOME}\n          className=\"flex items-center gap-2 group\"\n        >\n          <Logo\n            variant=\"lockup\"\n            size=\"md\"\n\n            /* 🔥 ICON ANIMATION */\n            iconClassName=\"\n              text-accent text-[1.1rem]\n              transition-transform duration-300 ease-out\n              group-hover:-translate-y-[2px]\n            \"\n\n            /* ❌ NO HOVER EFFECT ON TEXT */\n            wordmarkClassName=\"\n              text-text-primary font-semibold tracking-tight text-[1.5rem]\n            \"\n          />\n        </Link>\n      }\n      center={center}\n      right={\n        <div className=\"flex items-center gap-3 sm:gap-4\">\n          {/* LOGIN */}\n          <Button\n            as={Link}\n            to={ROUTES.LOGIN}\n            variant=\"secondary\"\n            size=\"sm\"\n            className=\"px-4\"\n          >\n            Log In\n          </Button>\n\n          {/* SIGNUP */}\n          <Button\n            as={Link}\n            to={ROUTES.SIGNUP}\n            variant=\"primary\"\n            size=\"sm\"\n            className=\"rounded-full px-5\"\n          >\n            Get Started\n          </Button>\n        </div>\n      }\n    />\n  );\n};\n\nexport default PublicHeader;","import React from \"react\";\nimport clsx from \"clsx\";\nimport { PublicFooter } from \"../footer\";\nimport { PublicHeader } from \"../header\";\n\nexport type MarketingShellProps = {\n  children: React.ReactNode;\n  className?: string;\n  showFooter?: boolean;\n  showHeader?: boolean;\n};\n\nexport const MarketingShell: React.FC<MarketingShellProps> = ({\n  children,\n  className,\n  showFooter = true,\n  showHeader = true,\n}) => {\n  return (\n    <div\n      className={clsx(\n        \"min-h-screen flex flex-col bg-background text-text-primary antialiased\",\n        \"selection:bg-accent/20 selection:text-accent\",\n        className\n      )}\n    >\n      {/* 🔝 HEADER */}\n      {showHeader && <PublicHeader />}\n\n      {/* 🧠 MAIN CONTENT */}\n      <main className=\"flex-1 flex flex-col pt-16\">\n        {/* 👆 this padding fixes content hiding under fixed header */}\n\n        <div className=\"unio-layout w-full\">\n          <div className=\"unio-container-marketing w-full\">\n            {children}\n          </div>\n        </div>\n      </main>\n\n      {/* 🔻 FOOTER */}\n      {showFooter && (\n        <div className=\"shrink-0\">\n          <PublicFooter />\n        </div>\n      )}\n    </div>\n  );\n};\n"]}
