AAAA,OACF;AAAA,MAIF,MAAA;AAAA,MAGA,KAAA,kBACEN,IAAAA,CAAC,KAAA,EAAA,EAAI,WAAU,kCAAA,EAMb,QAAA,EAAA;AAAA,wBAAAC,GAAAA,CAAC,IAAA,EAAA,EAAK,EAAA,EAAII,MAAAA,CAAO,KAAA,EACf,QAAA,kBAAAJ,GAAAA,CAAC,MAAA,EAAA,EAAO,OAAA,EAAQ,WAAA,EAAY,IAAA,EAAK,IAAA,EAAK,oBAEtC,CAAA,EACF,CAAA;AAAA,wBAGAA,GAAAA,CAAC,IAAA,EAAA,EAAK,EAAA,EAAII,MAAAA,CAAO,QACf,QAAA,kBAAAJ,GAAAA,CAAC,MAAA,EAAA,EAAO,OAAA,EAAQ,WAAU,IAAA,EAAK,IAAA,EAAK,SAAA,EAAU,cAAA,EAAe,yBAE7D,CAAA,EACF;AAAA,OAAA,EAEF;AAAA;AAAA,GAEJ;AAEJ,CAAA;ACpDO,IAAM,iBAAgD,CAAC;AAAA,EAC5D,QAAA;AAAA,EACA,SAAA;AAAA,EACA,UAAA,GAAa,IAAA;AAAA,EACb,UAAA,GAAa;AACf,CAAA,KAAM;AACJ,EAAA,uBACED,IAAAA;AAAA,IAAC,KAAA;AAAA,IAAA;AAAA,MACC,SAAA,EAAWG,KAAAA;AAAA,QACT,wEAAA;AAAA,QACA,8CAAA;AAAA,QACA;AAAA,OACF;AAAA,MAGC,QAAA,EAAA;AAAA,QAAA,UAAA,oBAAcF,IAAC,YAAA,EAAA,EAAa,CAAA;AAAA,wBAG7BA,GAAAA,CAAC,MAAA,EAAA,EAAK,SAAA,EAAU,4BAAA,EAGd,0BAAAA,GAAAA,CAAC,KAAA,EAAA,EAAI,SAAA,EAAU,oBAAA,EACb,0BAAAA,GAAAA,CAAC,KAAA,EAAA,EAAI,WAAU,iCAAA,EACZ,QAAA,EACH,GACF,CAAA,EACF,CAAA;AAAA,QAGC,UAAA,oBACCA,GAAAA,CAAC,KAAA,EAAA,EAAI,WAAU,UAAA,EACb,QAAA,kBAAAA,GAAAA,CAAC,YAAA,EAAA,EAAa,CAAA,EAChB;AAAA;AAAA;AAAA,GAEJ;AAEJ","file":"index.js","sourcesContent":["import React from \"react\";\nimport { Text } from \"@unio/ui\";\nimport { FooterLinkItem } from \"./types\";\n\nexport const FooterColumn: React.FC<{ title: string; items: readonly FooterLinkItem[] }> = ({ title, items }) => {\n  if (!items?.length) return null;\n  return (\n    <div className=\"flex flex-col gap-5 min-w-[140px]\">\n      <Text className=\"text-caption text-text-primary\">\n        {title}\n      </Text>\n      <ul className=\"flex flex-col gap-3\">\n        {items.map(({ href, label }) => (\n          <li key={label}>\n            <a href={href} className=\"text-sm text-text-secondary hover:text-accent transition-colors font-medium\">\n              {label}\n            </a>\n          </li>\n        ))}\n      </ul>\n    </div>\n  );\n};\n","import React from \"react\";\nimport { Text, Logo } from \"@unio/ui\";\nimport { ROUTES } from \"@unio/lib\";\n\nexport const FooterBrand: React.FC<{ variant: \"lockup\" | \"mark\" | \"wordmark\" }> = ({ variant }) => (\n  <div className=\"flex flex-col gap-5 max-w-[280px]\">\n    <a href={ROUTES.HOME} className=\"inline-block w-fit focus-visible:outline-accent\">\n      <Logo variant={variant} size=\"sm\" />\n    </a>\n    <Text size=\"medium\" tone=\"muted\" className=\"opacity-80 leading-relaxed\">\n      Building the future of professional connection through spatial intelligence.\n    </Text>\n  </div>\n);\n","import React from \"react\";\nimport { FiTwitter, FiInstagram, FiLinkedin } from \"react-icons/fi\";\nimport { clsx, type ClassValue } from \"clsx\";\nimport { twMerge } from \"tailwind-merge\";\n\nfunction cn(...inputs: ClassValue[]) {\n  return twMerge(clsx(inputs));\n}\n\ninterface FooterSocialsProps {\n  links: {\n    twitter: string;\n    instagram: string;\n    linkedin: string;\n  };\n  className?: string;\n}\n\nexport const FooterSocials: React.FC<FooterSocialsProps> = ({ links, className }) => {\n  const socialItems = [\n    { icon: <FiTwitter />, href: links.twitter, label: \"Twitter\" },\n    { icon: <FiInstagram />, href: links.instagram, label: \"Instagram\" },\n    { icon: <FiLinkedin />, href: links.linkedin, label: \"LinkedIn\" },\n  ];\n\n  return (\n    <div className={cn(\"flex items-center gap-1\", className)}>\n      {socialItems.map((social) => (\n        <a\n          key={social.label}\n          href={social.href}\n          target=\"_blank\"\n          rel=\"noopener noreferrer\"\n          aria-label={social.label}\n          className={cn(\n            \"p-2 rounded-lg transition-all duration-200\",\n            \"text-text-secondary hover:text-accent hover:bg-accent/5\",\n            \"focus-visible:ring-2 focus-visible:ring-accent focus-visible:ring-offset-2 outline-none\",\n            \"active:scale-95\" // Subtle \"press\" effect used by top companies\n          )}\n        >\n          {/* We ensure the icon inherits the parent text color and size */}\n          <span className=\"text-xl flex items-center justify-center\">\n            {social.icon}\n          </span>\n        </a>\n      ))}\n    </div>\n  );\n};\n\nexport default FooterSocials;\n","import React from \"react\";\nimport { Text } from \"@unio/ui\";\n\nconst YEAR = new Date().getFullYear();\n\nexport const FooterBottom = () => (\n  <div className=\"mt-16 pt-8 border-t border-border-subtle flex flex-col md:flex-row items-center justify-between gap-6\">\n    {/* ✅ Pure Text (Span) wrapping a Time element */}\n    <Text size=\"tiny\" className=\"text-text-tertiary font-medium\">\n      © <time dateTime={YEAR.toString()}>{YEAR}</time> Unio Technologies Inc. All rights reserved.\n    </Text>\n\n    <div className=\"flex items-center gap-6\">\n      <button \n        type=\"button\"\n        className=\"text-[10px] font-bold uppercase tracking-widest text-text-tertiary hover:text-accent transition outline-none focus-visible:text-accent\"\n      >\n        English (UK)\n      </button>\n\n      {/* ✅ Pure Text (Span) with custom tabular classes */}\n      <Text size=\"tiny\" className=\"text-text-tertiary opacity-40 tabular-nums\">\n        v2.0.26\n      </Text>\n    </div>\n  </div>\n);\n","import React, { memo } from \"react\";\nimport clsx from \"clsx\";\nimport { LINKS, FOOTER_LINKS } from \"@unio/lib\";\nimport { PublicFooterProps } from \"./types\";\nimport { FooterColumn } from \"./FooterColumn\";\nimport { FooterBrand } from \"./FooterBrand\";\nimport { FooterSocials } from \"./FooterSocials\";\nimport { FooterBottom } from \"./FooterBottom\";\n\nexport const PublicFooter: React.FC<PublicFooterProps> = memo(({\n  className,\n  containerClassName,\n  showTopBorder = true,\n  brandVariant = \"lockup\",\n  socialLinks,\n}) => {\n  const links = {\n    twitter: socialLinks?.twitter ?? LINKS.TWITTER,\n    instagram: socialLinks?.instagram ?? LINKS.INSTAGRAM,\n    linkedin: socialLinks?.linkedin ?? LINKS.LINKEDIN,\n  };\n\n  return (\n    <footer className={clsx(\"w-full shrink-0 bg-background\", showTopBorder && \"border-t border-border-faint\", className)}>\n      <div className=\"unio-layout\">\n        <div className={clsx(\"unio-container-marketing py-16 lg:py-24 footer-normalize\", containerClassName)}>\n          <nav className=\"flex flex-col lg:flex-row justify-between gap-16 lg:gap-8\">\n            {/* LEFT: BRANDING */}\n            <div className=\"flex flex-col gap-8\">\n              <FooterBrand variant={brandVariant} />\n              <FooterSocials links={links} />\n            </div>\n\n            {/* RIGHT: NAVIGATION */}\n            <div className=\"grid grid-cols-2 sm:grid-cols-4 gap-12 lg:gap-16 xl:gap-24\">\n              <FooterColumn title=\"Company\" items={FOOTER_LINKS.company} />\n              <FooterColumn title=\"Platform\" items={FOOTER_LINKS.resources} />\n              <FooterColumn title=\"Legal\" items={FOOTER_LINKS.legal} />\n              <FooterColumn title=\"Standards\" items={FOOTER_LINKS.compliance} />\n            </div>\n          </nav>\n\n          <FooterBottom />\n        </div>\n      </div>\n    </footer>\n  );\n});\n\nPublicFooter.displayName = \"PublicFooter\";\n","import React, { memo } from \"react\";\nimport { clsx } from \"clsx\";\n\nexport interface HeaderShellProps {\n  left?: React.ReactNode;\n  center?: React.ReactNode;\n  right?: React.ReactNode;\n  className?: string;\n\n  /**\n   * Layout variants\n   * default → standard app width\n   * marketing → wider landing pages\n   * full → edge-to-edge (rare use)\n   */\n  variant?: \"default\" | \"marketing\" | \"full\";\n}\n\nconst containerVariants = {\n  default: \"unio-container\",\n  marketing: \"unio-container-marketing\",\n  full: \"w-full px-[var(--container-padding-fluid)]\",\n};\n\nexport const PublicHeaderShell: React.FC<HeaderShellProps> = ({\n  left,\n  center,\n  right,\n  className,\n  variant = \"marketing\",\n}) => {\n  return (\n    <header\n      role=\"banner\"\n      className={clsx(\n        \"fixed top-0 left-0 right-0 z-50 w-full\",\n        \"backdrop-blur-xl\",\n        \"bg-[hsl(var(--bg-0)/0.7)]\",\n        \"border-b border-[hsl(var(--accent-1)/0.25)]\",\n        className\n      )}\n    >\n      <div className=\"unio-layout\">\n        <nav\n          className={clsx(\n            containerVariants[variant],\n            \"flex h-16 items-center justify-between\"\n          )}\n          aria-label=\"Primary\"\n        >\n          {/* LEFT */}\n          <div className=\"flex items-center min-w-[120px]\">\n            {left}\n          </div>\n\n          {/* CENTER */}\n          <div className=\"hidden md:flex flex-1 items-center justify-center\">\n            {center}\n          </div>\n\n          {/* RIGHT */}\n          <div className=\"flex items-center justify-end gap-3 min-w-[120px]\">\n            {right}\n          </div>\n        </nav>\n      </div>\n\n      {/* ✨ subtle gradient divider */}\n      <div className=\"pointer-events-none absolute bottom-0 left-0 right-0 flex justify-center\">\n        <div className=\"h-px w-[85%] bg-gradient-to-r from-transparent via-[hsl(var(--accent-1))] to-transparent\" />\n      </div>\n    </header>\n  );\n};\n\nexport default memo(PublicHeaderShell);","import React from \"react\";\nimport { Link } from \"react-router-dom\";\nimport { Logo, Button } from \"@unio/ui\";\nimport { ROUTES } from \"@unio/lib\";\nimport { PublicHeaderShell } from \"./PublicHeaderShell\";\n// import { ThemeToggle } from \"@/components/ThemeToggle\"; // optional\n\nexport type PublicHeaderProps = {\n  className?: string;\n  center?: React.ReactNode;\n};\n\nexport const PublicHeader: React.FC<PublicHeaderProps> = ({\n  className,\n  center,\n}) => {\n  return (\n    <PublicHeaderShell\n      className={className}\n      variant=\"marketing\"\n\n      /* ---------------- LEFT ---------------- */\n      left={\n        <Link\n          to={ROUTES.HOME}\n          className=\"flex items-center gap-2 hover:opacity-90 transition\"\n        >\n          <Logo\n            variant=\"lockup\"\n            size=\"md\"\n            iconClassName=\"text-accent\"\n            wordmarkClassName=\"text-text-primary font-semibold\"\n          />\n        </Link>\n      }\n\n      /* ---------------- CENTER ---------------- */\n      center={center}\n\n      /* ---------------- RIGHT ---------------- */\n      right={\n        <div className=\"flex items-center gap-3 sm:gap-4\">\n          \n          {/* 🌙 Theme toggle (plug-and-play) */}\n          {/* <ThemeToggle /> */}\n\n          {/* LOGIN */}\n          <Link to={ROUTES.LOGIN}>\n            <Button variant=\"secondary\" size=\"sm\">\n              Log In\n            </Button>\n          </Link>\n\n          {/* CTA */}\n          <Link to={ROUTES.SIGNUP}>\n            <Button variant=\"primary\" size=\"sm\" className=\"rounded-full\">\n              Get Started\n            </Button>\n          </Link>\n\n        </div>\n      }\n    />\n  );\n};\n\nexport default PublicHeader;","import React from \"react\";\nimport clsx from \"clsx\";\nimport { PublicFooter } from \"../footer\";\nimport { PublicHeader } from \"../header\";\n\nexport type MarketingShellProps = {\n  children: React.ReactNode;\n  className?: string;\n  showFooter?: boolean;\n  showHeader?: boolean;\n};\n\nexport const MarketingShell: React.FC<MarketingShellProps> = ({\n  children,\n  className,\n  showFooter = true,\n  showHeader = true,\n}) => {\n  return (\n    <div\n      className={clsx(\n        \"min-h-screen flex flex-col bg-background text-text-primary antialiased\",\n        \"selection:bg-accent/20 selection:text-accent\",\n        className\n      )}\n    >\n      {/* 🔝 HEADER */}\n      {showHeader && <PublicHeader />}\n\n      {/* 🧠 MAIN CONTENT */}\n      <main className=\"flex-1 flex flex-col pt-16\">\n        {/* 👆 this padding fixes content hiding under fixed header */}\n\n        <div className=\"unio-layout w-full\">\n          <div className=\"unio-container-marketing w-full\">\n            {children}\n          </div>\n        </div>\n      </main>\n\n      {/* 🔻 FOOTER */}\n      {showFooter && (\n        <div className=\"shrink-0\">\n          <PublicFooter />\n        </div>\n      )}\n    </div>\n  );\n};\n"]}
